public enum Status {
	OPEN,     // value in DB is 0 (ordinal = 0)
	REVIEW,   // value in DB is 1 (ordinal = 1)
	APPROVED; // value in DB is 2 (ordinal = 2)
}


public enum Status {
	OPEN,     // value in DB is OPEN
	REVIEW,   // value in DB is REVIEW
	APPROVED; // value in DB is APPROVED
}


public enum Status {
	OPEN ("O"),     // value in DB is O
	REVIEW ("R"),   // value in DB is R
	APPROVED ("A"); // value in DB is A

	private String code;

	private Status(String code) {
		this.code = code;
	}

	public String getCode() {
		return this.code;
	}
}


@Entity
public class Article {

	private Status status;
}


@Converter(autoApply = true)
public class StatusConverter implements AttributeConverter<Status, String> {

	@Override
	public String convertToDatabaseColumn(Status status) {
		if (status == null) {
			return null;
		}
		return status.getCode();
	}

	@Override
	public Status convertToEntityAttribute(String code) {
		if (code == null) {
			return null;
		}
		return Stream.of(Status.values())
			.filter(s -> s.getCode().equals(code))
			.findFirst()
			.orElseThrow(IllegalArgumentException::new);
	}
}
